pure fn variance(nums: List[Number]) -> Number {
    avg = mean(nums)
    total = 0
    for n in nums { total = total + pow(n - avg, 2) }
    return total / length(nums)
}
pure fn std_dev(nums: List[Number]) -> Number {
    return sqrt(variance(nums))
}
