pure fn sort_pairs(pairs: Text) -> Text {
    sorted = []
    for p in pairs {
        inserted = false
        for i in range(0, length(sorted)) {
            if to_number(split(get(sorted, i), ",")[1]) > to_number(split(p, ",")[1]) {
                sorted = insert_at(sorted, i, p)
                inserted = true
                break
            }
        }
        if not inserted { sorted = append(sorted, p) }
    }
    return join(sorted, ";")
}
