    parts = split_by(pairs, ";")
    first = to_number(split(get(parts, 0), ",")[1])
    last = to_number(split(get(parts, length(parts) - 1), ",")[1])
    if first < last { return "north-south" }
    if first > last { return "south-north" }
    return "flat"
}
